import random

def simulate_fish_trap_flow(num_fish=100, weir_positions=[10, 25, 40, 60], trap_length=100):
    fish_positions = {i: random.randint(0, trap_length) for i in range(num_fish)}
    caught_fish = []

    for step in range(trap_length):
        for fish_id, pos in list(fish_positions.items()):
            if pos == step:
                if step in weir_positions:
                    caught_fish.append(fish_id)
                fish_positions.pop(fish_id)

    return {
        "initial_fish": num_fish,
        "caught_fish": caught_fish,
        "percentage_caught": (len(caught_fish) / num_fish) * 100
    }

# Example usage
result = simulate_fish_trap_flow(num_fish=200)
print(f"Caught {result['percentage_caught']:.1f}% of fish.")

This function simulates the movement of fish through a trap system with defined weir positions, returning the number of fish caught and the percentage of the total.
